	const fields = entityDef.fields;
	const requiredFields = Object.keys(fields).filter(
		(k) => fields[k].required && !fields[k].pk,
	);
	const properties = {};
	for (const [fieldName, fieldDef] of Object.entries(fields)) {
		if (fieldDef.pk) {
