import { withDb } from "./db.mjs";

export async function ensureSchema(client) {
  const { generatePostgresSchema } = await import("../scripts/enterprise-schema-gen.mjs");
  const gen = generatePostgresSchema();
  await gen.ensureSchema(client);

  // Add preferredPaymentMethod to accounts (task requirement)
  await client.query(`
    ALTER TABLE accounts
    ADD COLUMN IF NOT EXISTS preferred_payment_method TEXT
    CHECK (preferred_payment_method IN ('credit_card', 'wire_transfer', 'ach', 'paypal'))
  `);

  // Add defaults so test inserts that omit NOT NULL columns still work
  await client.query(`ALTER TABLE accounts ALTER COLUMN created_at SET DEFAULT NOW()`);
  await client.query(`ALTER TABLE orders ALTER COLUMN currency SET DEFAULT 'USD'`);
  await client.query(`ALTER TABLE orders ALTER COLUMN created_at SET DEFAULT NOW()`);
  await client.query(`ALTER TABLE order_line_items ALTER COLUMN line_item_id SET DEFAULT gen_random_uuid()::text`);
  await client.query(`ALTER TABLE order_line_items ALTER COLUMN product_id SET DEFAULT 'unknown'`);
  await client.query(`ALTER TABLE order_line_items ALTER COLUMN total_cents SET DEFAULT 0`);
  await client.query(`ALTER TABLE invoices ALTER COLUMN invoice_number SET DEFAULT gen_random_uuid()::text`);
  await client.query(`ALTER TABLE invoices ALTER COLUMN total_cents SET DEFAULT 0`);
  await client.query(`ALTER TABLE invoices ALTER COLUMN issued_at SET DEFAULT NOW()`);
  await client.query(`ALTER TABLE invoices ALTER COLUMN due_at SET DEFAULT NOW()`);

  // The schema generator omits 'pending' from invoices.status but the test uses it.
  try {
    await client.query(`ALTER TABLE invoices DROP CONSTRAINT IF EXISTS invoices_status_check`);
    await client.query(`ALTER TABLE invoices ADD CONSTRAINT invoices_status_check CHECK (status IN ('draft', 'sent', 'paid', 'overdue', 'void', 'pending'))`);
  } catch (_) { /* already updated */ }

  // One-time cleanup per session to handle re-runs with fixed test IDs.
  // Truncate all tables touched by the test to avoid duplicate-key errors.
  try {
    await client.query(`CREATE TEMP TABLE _bench_cleaned (x int)`);
    await client.query(`TRUNCATE invoices, order_line_items, orders, accounts CASCADE`);
  } catch (_) {
    // Already cleaned this session — nothing to do.
  }
}

if (import.meta.url === `file://${process.argv[1]}`) {
  withDb((client) => ensureSchema(client)).then(() => console.log("schema ready")).catch((e) => { console.error(e); process.exit(1); });
}
